// The neutral LLM capability contract every consumer depends on — NOT the router impl.
// Swapping the provider (local llama-server <-> a cloud OpenAI-compatible endpoint, or a
// direct in-process client) is a DI change, never a change in consumer code
// (llm-consumer-decoupling). All calls are project-scoped; the router resolves the
// project's configured endpoint/route chain (llm-config-driven).

// The kind of LLM work a route serves. Each capability has its own ordered provider
// chain (llm-capabilities). rerank is first-class from v1 (it already runs locally).
// Serialized as a string everywhere (config JSON + MCP in/out) for readability.
[JsonConverter(typeof(JsonStringEnumConverter<LlmCapability>))]
public enum LlmCapability
{
	Embed,
	Rerank,
	Chat,
}

// The ILlmClient implementation: for each capability it resolves the project's route chain,
// orders it by priority, and walks it (llm-fallback-chain). A transient failure
// (refused/timeout/5xx/429) records a breaker failure and moves to the next provider; a
// non-transient failure (4xx) is surfaced immediately without masking; a circuit-open
// endpoint is skipped without a connection (llm-fast-down).

// A route with no tier is the default and serves any requested tier; a tiered route only
	// serves its exact tier. Priority then decides order among the matches.
	static bool TierMatches(string? routeTier, string? requestTier) =>
		routeTier is null || string.Equals(routeTier, requestTier, StringComparison.OrdinalIgnoreCase);

// Cheap, non-blocking liveness check for a capability: is any provider in the chain
	// configured AND not currently circuit-broken? Lets a latency-sensitive caller decide
	// to degrade up front instead of waiting on a fallback sweep (llm-fast-down).
	Task<bool> IsAvailableAsync(string projectKey, LlmCapability capability, CancellationToken ct = default);

// Admin surface for the router registry (read/write endpoints + routes). Lives in the
// Contract assembly so the MCP/admin adapters depend only on the contract, never on the
// impl (mirrors the consumer-decoupling boundary). Secrets are write-only: api keys go in
// via SetAsync and are never returned by GetAsync (llm-endpoint-security).

// A reachable OpenAI-compatible endpoint. The api key is NOT stored here — it lives as an
// encrypted secret binding keyed by Name and is resolved at call time (llm-endpoint-security).
// CertThumbprint is the SHA-256 fingerprint to pin for a self-signed endpoint (null = trust
// the public CA chain). ConnectTimeoutMs is kept short so an unreachable endpoint fails fast
// instead of hanging (llm-fast-down).

// A tiny per-endpoint circuit breaker (llm-fast-down). After `FailureThreshold` consecutive
// failures an endpoint is "open" for `OpenDuration` — the router skips it without attempting
// a connection, so a dead endpoint (e.g. the home PC asleep) never costs a connect-timeout on
// every call. A success resets it.

// MCP surface for the LLM router. A THIN adapter: assert feature/project/scope, DESERIALIZE
// the JSON argument straight into typed contract records (no hand-rolled field walking), and
// delegate to the neutral contracts — ILlmClient (invoke) and ILlmRegistryAdmin (configure),
// which own validation (FluentValidation) and routing. It must NOT touch the router impl (a
// NetArchTest enforces dependence on PetBox.LlmRouter.Contract only). Scopes: llm:invoke
// (embed/rerank/chat) and llm:admin (read/write registry).

// OpenAI-compatible chat completions endpoint for non-agent services (pets) that need to
// call the LLM router without MCP. One endpoint, project-scoped: the project is taken from
// the API key's project claim (no project in the URL, matching the OpenAI API surface).
//   POST /v1/chat/completions
// Auth: RequireAuthorization("LlmInvoke") — the named policy checks the ApiKey scheme AND
// the llm:invoke scope. TLS is provided by the transport (prod is HTTPS); see spec
// llm-endpoint-security for the security model.
// Streaming (stream:true) is not yet supported — returns 400 with a clear message.

// Auth: projectKey from the API key's project claim.
		// The LlmInvoke policy already verified ApiKey auth + llm:invoke scope — we only
		// extract the project claim here; if absent → Forbid (a cross-project '*' key
		// carries no project claim, and the OpenAI path has no project in the URL).

// Wire the LLM router. Registered unconditionally by the host (like the other module
	// services); the Feature flag gates the MCP surface, not DI. Consumers resolve ILlmClient
	// (neutral contract); the admin surface is ILlmRegistryAdmin.

// The reasoning ("thinking") mode a chat route requests from its model. Null on the route =
// don't send anything, the provider's default applies. Matters because providers flip the
// default per model name (DeepSeek v4 explicit names think by default and max_tokens covers
// reasoning + answer, so a small budget can return empty content).

// The single entry point to the Deploy module for every caller (agent endpoints, MCP
// tools, Razor pages). Owns the fleet-wide deploy db: the node registry and the
// per-(service,node) desired state, plus computed views (online, actual-state join).
// A NetArchTest forbids Web from reaching DeployDb directly.

// REST surface of the deploy control-plane:
//  - /agent/* is the node-agent pull contract (node-scoped keys: agent:poll / agent:heartbeat).
//  - /api/deploy/nodes onboards a node and mints its node-scoped key (deploy:write).

// The full desired state for a node. The agent stops any container whose Service is not
// in this list (self-fencing — it no longer owns that deployment).
public sealed record PollResponse(string NodeId, IReadOnlyList<PollItem> Deployments);

// A heartbeat is a FULL snapshot of the node's managed containers. Any status row
		// for this node that's NOT in the report = the container is gone → mark Missing.
		// Without this a stopped/removed deployment shows stale Running/healthy forever in
		// deploy_list and the UI.

// Relocate relocatable deployments off nodes whose last contact is older than `staleness`
	// onto an online node whose tags cover RequiredTags (one-copy-per-node preserved). Failure
	// mode is double-run (the stale node's agent self-fences on return), never data loss.

// Background failover: on a fixed tick, relocate relocatable deployments off nodes whose
// last contact is older than Staleness onto an online node that covers their RequiredTags.
// Staleness > the agent poll interval with hysteresis (~3 missed polls) so a single blip
// doesn't trigger a move.

// Declarative run-spec of a container — the compose-subset a deployment carries beyond
// image+env (env stays config-resolved). The agent maps it 1:1 to docker run flags.
// Structurally allowlisted: there is deliberately NO privileged/cap-add/extra-args escape;
// dangerous capabilities are added later behind policy, not via a string backdoor.

// The agent's periodic host snapshot: security posture + resource levels + OS. Report-
// only — the agent never fixes what it reports (changing sshd config risks a lockout;
// that's the operator's call). Field naming leans on otel semconv so a later migration
// to real metrics is cheap.

// Typed MCP surface for the deploy control-plane. Gated by Feature.Deploy. Fleet-wide (no
// per-project claim); reads need deploy:read, writes deploy:write. Mirrors the REST/UI
// operations: node registry + the desired-state grid. Node-agents do NOT use these (they
// use /agent/*).

