// Orphan file reclamation for the per-project temporal stores (tasks / memory /
		// sessions). ProjectDeletion cascades away a deleted project's Core-DB metadata but
		// leaves its on-disk `.db` files behind; these mop them up eventually-consistently,
		// mirroring the Data/Log orphan services. Unconditional data hygiene (like
		// BackupService) — the factories above are unconditional, and a file can outlive a
		// since-disabled feature.

// Canonical PetBox auth header. The server also accepts the legacy X-YobaConf-ApiKey
	// and `Authorization: Bearer/Token`, but new clients send X-Api-Key.
	public const string ApiKeyHeader = "X-Api-Key";

// Entry point for the PetBox .NET SDK. Owns an authenticated HttpClient (built via the shared
// PetBoxTransport) and exposes the typed per-surface clients. Today: Data. Config has its own
// specialized provider package (PetBox.Client.Config) built on the same transport.

// Typed client for the PetBox Data module — raw parameterized SQL over HTTP plus DataDb
// provisioning. The server is a dumb pass-through: it knows nothing about the caller's POCOs,
// it just runs the SQL against the project's SQLite file. linq2db query-building lives in the
// PetBox.Client.Data.Linq2Db package on top of QueryAsync.

// Last-known-good (LKG) disk cache for the config provider. Persists the flattened config
// tree + its ETag so a host can boot on its last good config after a restart even while
// petbox is unreachable (DC-outage survival). Every method here is best-effort: cache I/O
// must never break config loading, so read failures return null and write failures are
// swallowed (Debug at most). A corrupt/unreadable file is treated as "no cache".

// HTTP timeout for the config provider's own HttpClient. Kept short (10s default, vs the
	// framework's 100s) so a slow/unreachable petbox never blocks host startup for long —
	// the initial fetch fails fast and, if a disk cache exists, boot continues on LKG data.
	public TimeSpan Timeout { get; set; } = TimeSpan.FromSeconds(10);

	// When true, initial load failures (409, auth errors, network errors) don't throw —
	// the provider starts with empty data and retries on the next poll tick. Matches the
	// ConfigurationBuilder `optional: true` convention. Default false: missing config at
	// startup is usually a broken-deploy signal, fail-fast surfaces it.

public static void MapDeployEndpoints(this IEndpointRouteBuilder app)
	{
		app.MapGet("/agent/poll", PollAsync)
			.Produces<PollResponse>()
			.Produces<ErrorResponse>(StatusCodes.Status400BadRequest)
			.RequireAuthorization("ApiKey");
		app.MapPost("/agent/heartbeat", HeartbeatAsync)
			.Produces<OkResponse>()
			.Produces<ErrorResponse>(StatusCodes.Status400BadRequest)
			.RequireAuthorization("ApiKey");
		app.MapPost("/api/deploy/nodes", EnrollNodeAsync)
			.Produces<NodeEnrollResponse>()
			.Produces<ErrorResponse>(StatusCodes.Status400BadRequest)
			.RequireAuthorization("ApiKey");
	}

builder.Services.AddMcpServer()
			.WithHttpTransport(o => o.Stateless = true)
			// Schema-honest registration: nullable record properties are NOT marked
