			.WithSchemaHonestToolsFromAssembly(typeof(Program).Assembly, mcpJson, PetBox.Web.Mcp.McpOutputSchema.NullableAware)

// Marks a deployment as a SITE: a web app served behind the node's reverse proxy.
// Domain is the public hostname; Port is the loopback port the proxy forwards to
// (defaulted at normalize time from the host port of the first ports entry). The node
// agent keeps the host reverse-proxy (Caddy) config in line with this route.

// Copy the SDK's default tool-serialization options (camelCase, null-ignore, MCP
		// converters) and only relax the text encoder: the default escapes every non-ASCII
		// char (Cyrillic -> \uXXXX), making tool-result JSON unreadable. Allow common ranges
		// (not UnsafeRelaxed) so output is human-readable while HTML-sensitive chars stay escaped.

// How often to re-poll for changes. Each poll uses `If-None-Match: <etag>`, so 304s
	// are cheap. Set to TimeSpan.Zero to disable polling (one-shot load at startup only).
	public TimeSpan RefreshInterval { get; set; } = TimeSpan.FromMinutes(5);

// Stateful singletons shared across requests: the breaker's health state and the
		// per-endpoint cert-pinned HttpClient cache must outlive a single scope.
		services.TryAddSingleton<EndpointBreaker>();
		services.TryAddSingleton<CertPinningHttpClientProvider>();

// A node is "online" if its last heartbeat is within this window. The agent poll
	// interval is well under this; failover (slice 4) uses a larger staleness threshold.
	private static readonly TimeSpan OnlineWindow = TimeSpan.FromSeconds(120);
